(function(){
  'use strict';
  const $=(s,r=document)=>r.querySelector(s);
  const API='/api/contributions';
  const state={ready:false,page:1,pageSize:20,search:'',year:'',campaign:null,catalogs:null};
  const esc=v=>String(v??'').replace(/[&<>"']/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#039;'}[c]));
  const num=v=>new Intl.NumberFormat('vi-VN').format(Number(v||0));
  const money=v=>new Intl.NumberFormat('vi-VN').format(Number(v||0));
  const toast=(m,t='success')=>typeof showToast==='function'?showToast(m,t):console.log(m);
  async function req(url,opt={}){ if(typeof api==='function')return api(url,opt); const token=window.App?.token||localStorage.getItem('thon09_token')||''; const init={method:opt.method||'GET',headers:{Accept:'application/json',Authorization:token?'Bearer '+token:''}}; if(opt.body){init.headers['Content-Type']='application/json';init.body=JSON.stringify(opt.body);} const r=await fetch(url,init); const j=await r.json().catch(()=>null); if(!r.ok||j?.ok===false)throw new Error(j?.error?.message||'Không tải được dữ liệu'); return j?.data??j;}
  function can(action){const role=(window.App?.user?.role||'').toUpperCase(); if(['SUPER_ADMIN','ADMIN'].includes(role))return true; if(role==='OFFICER')return ['read','create','update'].includes(action); if(role==='VIEWER')return action==='read'; return true;}
  document.addEventListener('DOMContentLoaded',init);
  document.addEventListener('thon09:screen-change',e=>{if(e.detail?.screen==='contributions')load();});
  function init(){ if($('#contributionsScreen')?.classList.contains('active'))load(); }
  function shell(){const host=$('#contributionsScreen'); if(!host||state.ready)return; host.classList.remove('module-placeholder-screen'); host.innerHTML='<section id="contributionStats" class="dashboard-kpi-grid mb-3"></section><section id="contributionCharts" class="row g-3 mb-3"></section><section class="content-card module-filter-card"><div class="module-page-head"><div><h2>Đóng góp hộ</h2><p class="text-muted mb-0">Quản lý đợt thu và theo dõi công nợ từng hộ.</p></div><div class="d-flex gap-2 flex-wrap"><button id="contributionExportExcel" class="btn btn-outline-success" type="button"><i class="fa-solid fa-file-excel"></i> Excel</button><button id="contributionExportPdf" class="btn btn-outline-danger" type="button"><i class="fa-solid fa-file-pdf"></i> PDF</button><button id="contributionAddBtn" class="btn btn-success" type="button"><i class="fa-solid fa-plus"></i> Thêm đợt thu</button></div></div><div class="row g-2"><div class="col-md-6"><label class="form-label">Tìm kiếm</label><input id="contributionSearch" class="form-control" placeholder="Tên khoản thu, đợt thu, ghi chú..."></div><div class="col-md-3"><label class="form-label">Năm</label><input id="contributionYearFilter" type="number" class="form-control" placeholder="2026"></div><div class="col-md-3 d-flex align-items-end gap-2"><button id="contributionAddBtnInline" class="btn btn-success flex-fill" type="button"><i class="fa-solid fa-plus"></i> Thêm</button><button id="contributionResetBtn" class="btn btn-outline-secondary flex-fill" type="button"><i class="fa-solid fa-rotate-left"></i> Làm mới</button></div></div></section><section class="module-list-card household-list-card mt-3"><div class="module-list-head"><div><h3>Danh sách đợt thu</h3><span id="contributionsTotal">Tổng số: 0 đợt thu</span></div><div class="d-flex gap-2 align-items-center"><button id="contributionAddBtnList" class="btn btn-success btn-sm" type="button"><i class="fa-solid fa-plus"></i> Thêm đợt thu</button><select id="contributionsPageSize" class="form-select w-auto"><option>20</option><option>50</option><option>100</option></select></div></div><div class="table-responsive"><table class="table module-table align-middle mb-0"><thead><tr><th>STT</th><th>Khoản thu</th><th>Năm</th><th>Đợt</th><th>Mức thu</th><th>Hạn đóng</th><th>Đã nộp</th><th>Miễn giảm</th><th>Đã thu</th><th>Trạng thái</th><th class="text-end">Thao tác</th></tr></thead><tbody id="contributionsRows"></tbody></table></div><div id="contributionsPager" class="pager module-pager"></div></section><section id="contributionTrackingCard" class="module-list-card household-list-card mt-3 d-none"><div class="module-list-head"><div><h3 id="contributionTrackingTitle">Theo dõi hộ</h3><span id="contributionTrackingTotal">Tổng số: 0 hộ</span></div><select id="contributionPaymentFilter" class="form-select w-auto"><option value="">Tất cả</option><option value="UNPAID">Chưa nộp</option><option value="PAID">Đã nộp</option><option value="PARTIAL">Nộp một phần</option><option value="EXEMPT">Miễn giảm</option></select></div><div class="table-responsive"><table class="table module-table align-middle mb-0"><thead><tr><th>Mã hộ</th><th>Chủ hộ</th><th>Địa chỉ</th><th>Trạng thái</th><th>So tien</th><th>Con no</th><th>Ngay thu</th><th>Người thu</th><th>Biên lai</th><th class="text-end">Thao tác</th></tr></thead><tbody id="contributionTrackingRows"></tbody></table></div></section>'+campaignModal()+paymentModal(); bind(); state.ready=true;}
  function campaignModal(){return '<div class="modal fade" id="contributionModal" tabindex="-1"><div class="modal-dialog modal-xl"><form id="contributionForm" class="modal-content"><div class="modal-header"><h5 class="modal-title">Thong tin dot thu</h5><button type="button" class="btn-close" data-bs-dismiss="modal"></button></div><div class="modal-body"><input type="hidden" name="id"><div class="row g-3"><div class="col-md-4"><label class="form-label">Ma khoan thu</label><input name="campaign_code" class="form-control" disabled></div><div class="col-md-8"><label class="form-label">Ten khoan thu</label><input name="contribution_name" class="form-control" required></div><div class="col-md-4"><label class="form-label">Loai khoan thu</label><select name="contribution_type" id="contributionTypeInput" class="form-select"></select></div><div class="col-md-4"><label class="form-label">Tinh chat</label><select name="required_type" id="contributionRequiredInput" class="form-select"></select></div><div class="col-md-2"><label class="form-label">Nam</label><input name="year" type="number" class="form-control" required></div><div class="col-md-2"><label class="form-label">Dot thu</label><input name="period_name" class="form-control"></div><div class="col-md-4"><label class="form-label">Muc thu chuan</label><input name="amount" type="number" class="form-control"></div><div class="col-md-4"><label class="form-label">Don vi tinh</label><select name="unit_type" id="contributionUnitTypeInput" class="form-select"></select></div><div class="col-md-4"><label class="form-label">Hien thi don vi</label><input name="unit" class="form-control" value="VND/ho"></div><div class="col-md-4"><label class="form-label">Ngay bat dau</label><input name="start_date" type="date" class="form-control"></div><div class="col-md-4"><label class="form-label">Han thu</label><input name="due_date" type="date" class="form-control"></div><div class="col-md-4"><label class="form-label">Trang thai</label><select name="status" id="contributionStatusInput" class="form-select"></select></div><div class="col-md-4"><label class="form-label">Doi tuong phai thu</label><select name="target_mode" id="contributionTargetModeInput" class="form-select"></select></div><div class="col-md-2"><label class="form-label">Tu tuoi</label><input name="target_age_from" type="number" min="0" class="form-control"></div><div class="col-md-2"><label class="form-label">Den tuoi</label><input name="target_age_to" type="number" min="0" class="form-control"></div><div class="col-12"><label class="form-label">Doi tuong duoc mien</label><div id="contributionExemptionOptions" class="row g-2"></div></div><div class="col-md-6"><label class="form-label">Ghi chu doi tuong thu</label><input name="target_note" class="form-control"></div><div class="col-md-6"><label class="form-label">Ghi chu mien giam</label><input name="exemption_note" class="form-control"></div><div class="col-12"><label class="form-label">Ghi chu</label><textarea name="note" class="form-control" rows="2"></textarea></div></div></div><div class="modal-footer"><button type="button" class="btn btn-outline-secondary" data-bs-dismiss="modal">Dong</button><button class="btn btn-success" type="submit">Luu</button></div></form></div></div>';}
  function paymentModal(){return '<div class="modal fade" id="contributionPaymentModal" tabindex="-1"><div class="modal-dialog modal-lg"><form id="contributionPaymentForm" class="modal-content"><div class="modal-header"><h5 class="modal-title">Cập nhật đóng góp hộ</h5><button type="button" class="btn-close" data-bs-dismiss="modal"></button></div><div class="modal-body"><input type="hidden" name="campaign_id"><input type="hidden" name="household_id"><p id="contributionPaymentHousehold" class="fw-semibold"></p><div class="row g-3"><div class="col-md-4"><label class="form-label">Trạng thái</label><select name="payment_status" id="paymentStatusInput" class="form-select"></select></div><div class="col-md-4"><label class="form-label">Số tiền phải nộp</label><input name="expected_amount" type="number" class="form-control"></div><div class="col-md-4"><label class="form-label">Số tiền đã nộp</label><input name="paid_amount" type="number" class="form-control"></div><div class="col-md-4"><label class="form-label">Thu lan nay</label><input name="payment_amount" type="number" class="form-control"></div><div class="col-md-4"><label class="form-label">Số tiền giảm/miễn</label><input name="discount_amount" type="number" class="form-control"></div><div class="col-md-4"><label class="form-label">Ngày thu</label><input name="paid_at" type="date" class="form-control"></div><div class="col-md-4"><label class="form-label">Người thu</label><input name="collector_name" class="form-control"></div><div class="col-md-4"><label class="form-label">Hình thức thanh toán</label><select name="payment_method" id="paymentMethodInput" class="form-select"></select></div><div class="col-md-4"><label class="form-label">Số biên lai</label><input name="receipt_number" class="form-control"></div><div class="col-12"><label class="form-label">Ghi chú</label><textarea name="note" class="form-control" rows="2"></textarea></div></div></div><div class="modal-footer"><button type="button" class="btn btn-outline-secondary" data-bs-dismiss="modal">Đóng</button><button class="btn btn-success" type="submit">Lưu</button></div></form></div></div>';}
  function bind(){ $('#contributionSearch').addEventListener('input',debounce(e=>{state.search=e.target.value.trim();state.page=1;load();},300)); $('#contributionYearFilter').addEventListener('input',debounce(e=>{state.year=e.target.value.trim();state.page=1;load();},300)); $('#contributionsPageSize').addEventListener('change',e=>{state.pageSize=Number(e.target.value||20);state.page=1;load();}); $('#contributionResetBtn').onclick=()=>{Object.assign(state,{page:1,search:'',year:''});$('#contributionSearch').value='';$('#contributionYearFilter').value='';load();}; ['#contributionAddBtn','#contributionAddBtnInline','#contributionAddBtnList'].forEach(sel=>$(sel)?.addEventListener('click',()=>openCampaign())); $('#contributionForm').addEventListener('submit',saveCampaign); $('#contributionPaymentForm').addEventListener('submit',savePayment); $('#contributionPaymentFilter').onchange=()=>loadTracking(); $('#contributionExportExcel').onclick=()=>exportReport('excel'); $('#contributionExportPdf').onclick=()=>exportReport('pdf');}
  async function catalogs(){ if(state.catalogs)return state.catalogs; state.catalogs=await req(API+'/catalogs',{cacheTtl:60000}); fill('#contributionTypeInput',state.catalogs.categories,'Chon loai'); fill('#contributionRequiredInput',state.catalogs.required_types,'Chon tinh chat'); fill('#contributionStatusInput',state.catalogs.campaign_statuses,'Chon trang thai'); fill('#paymentStatusInput',state.catalogs.payment_statuses,'Chon trang thai'); fill('#paymentMethodInput',state.catalogs.payment_methods,'Chon hinh thuc'); fill('#contributionUnitTypeInput',state.catalogs.unit_types,'Chon don vi'); fill('#contributionTargetModeInput',state.catalogs.target_options,'Chon doi tuong'); renderExemptions(state.catalogs.exemption_options||[]); return state.catalogs; }
  function renderExemptions(items){const host=$('#contributionExemptionOptions'); if(!host)return; host.innerHTML=(items||[]).map(i=>'<label class="col-md-4 small d-flex gap-2 align-items-center"><input class="form-check-input m-0" type="checkbox" name="exemption_conditions" value="'+esc(i.value)+'"> <span>'+esc(i.label||i.value)+'</span></label>').join('');}
  function fill(sel,items,first){const el=$(sel); if(!el)return; el.innerHTML='<option value="">'+esc(first)+'</option>'+(items||[]).map(i=>'<option value="'+esc(i.value)+'">'+esc(i.label||i.value)+'</option>').join('');}
  function params(){const p=new URLSearchParams({page:state.page,pageSize:state.pageSize}); if(state.search)p.set('search',state.search); if(state.year)p.set('year',state.year); return p;}
  async function load(){ if(!can('read'))return; shell(); await catalogs(); try{const data=await req(API+'?'+params().toString(),{cacheTtl:3000}); render(data); dashboard();}catch(e){toast(e.message,'danger');} }
  function render(data){const rows=data.items||[]; $('#contributionsTotal').textContent='Tổng số: '+num(data.total)+' đợt thu'; $('#contributionsRows').innerHTML=rows.length?rows.map((r,i)=>row(r,(data.page-1)*data.pageSize+i+1)).join(''):'<tr><td colspan="11" class="text-center text-muted py-4">Chưa có dữ liệu đợt thu</td></tr>'; pager(data); if(typeof thon09SyncResponsiveTableLabels==='function')thon09SyncResponsiveTableLabels($('#contributionsScreen'));}
  function row(r,i){const actions='<button class="btn btn-sm btn-outline-secondary me-1" data-track="'+r.id+'" data-name="'+esc(r.contribution_name)+'"><i class="fa-solid fa-list-check"></i></button>'+(can('update')?'<button class="btn btn-sm btn-outline-primary me-1" data-edit="'+r.id+'"><i class="fa-solid fa-pen"></i></button>':'')+(can('delete')?'<button class="btn btn-sm btn-outline-danger" data-del="'+r.id+'"><i class="fa-solid fa-trash"></i></button>':''); return '<tr><td>'+i+'</td><td><strong>'+esc(r.campaign_code||'')+'</strong><div>'+esc(r.contribution_name)+'</div><div class="text-muted small">'+esc(r.contribution_type||'')+' - '+esc(r.required_type_label||'')+'</div></td><td>'+r.year+'</td><td>'+esc(r.period_name)+'</td><td>'+money(r.amount)+' '+esc(r.unit)+'</td><td>'+esc(r.start_date||'')+'<div class="small text-muted">'+esc(r.due_date||'')+'</div></td><td>'+num(r.paid_households)+'</td><td>'+num(r.exempt_households)+'</td><td>'+money(r.collected_amount)+'<div class="small text-muted">Nợ: '+money(r.debt_amount)+'</div></td><td><span class="badge text-bg-light">'+esc(r.status_label)+'</span></td><td class="text-end">'+actions+'</td></tr>';}
  function pager(data){const h=$('#contributionsPager'),page=Number(data.page||1),total=Number(data.totalPages||1); h.innerHTML='<button class="btn btn-sm btn-outline-secondary" '+(page<=1?'disabled':'')+'>Trước</button><span class="px-2">'+page+' / '+total+'</span><button class="btn btn-sm btn-outline-secondary" '+(page>=total?'disabled':'')+'>Sau</button>'; const b=h.querySelectorAll('button'); b[0].onclick=()=>{state.page--;load();}; b[1].onclick=()=>{state.page++;load();}; $('#contributionsRows').querySelectorAll('[data-track]').forEach(b=>b.onclick=()=>{state.campaign={id:Number(b.dataset.track),name:b.dataset.name};loadTracking();}); $('#contributionsRows').querySelectorAll('[data-edit]').forEach(b=>b.onclick=()=>openCampaign(b.dataset.edit)); $('#contributionsRows').querySelectorAll('[data-del]').forEach(b=>b.onclick=()=>removeCampaign(b.dataset.del));}
  async function dashboard(){try{const d=await req(API+'/dashboard',{cacheTtl:5000}); const m=d.metrics||{}, charts=d.charts||{}; $('#contributionStats').innerHTML=[['Tổng số hộ',m.total_households??m.households,'hộ','fa-house'],['Hộ phải đóng',m.due_households,'hộ','fa-users'],['Hộ được miễn',m.exempt,'hộ','fa-shield-heart'],['Đã nộp',m.paid,'hộ','fa-circle-check'],['Nộp một phần',m.partial,'hộ','fa-chart-pie'],['Chưa nộp',m.unpaid,'hộ','fa-clock'],['Tổng phải thu',money(m.gross_total),'VNĐ','fa-sack-dollar'],['Tổng được miễn',money(m.exempt_total),'VNĐ','fa-hand-holding-heart'],['Đã thu',money(m.collected),'VNĐ','fa-money-bill-wave'],['Còn phải thu',money(m.debt),'VNĐ','fa-hourglass-half']].map(c=>'<article class="dashboard-kpi-card"><span><i class="fa-solid '+c[3]+'"></i></span><div><p>'+c[0]+'</p><strong>'+c[1]+'</strong><em>'+c[2]+'</em></div></article>').join(''); renderCharts(charts);}catch(e){}}
  function renderCharts(charts){const host=$('#contributionCharts'); if(!host)return; const status=charts.by_status||[], finance=charts.financial||[]; host.innerHTML='<div class="col-lg-6"><section class="module-list-card h-100"><div class="module-list-head"><h3>Trạng thái hộ</h3></div>'+chartList(status,false)+'</section></div><div class="col-lg-6"><section class="module-list-card h-100"><div class="module-list-head"><h3>Tài chính</h3></div>'+chartList(finance,true)+'</section></div>';}
  function chartList(items,isMoney){const max=Math.max(1,...(items||[]).map(i=>Number(i.value||0))); return '<div class="p-3">'+(items||[]).map(i=>{const value=Number(i.value||0),w=Math.max(4,Math.round(value*100/max)); return '<div class="mb-2"><div class="d-flex justify-content-between small"><span>'+esc(i.label)+'</span><strong>'+(isMoney?money(value):num(value))+'</strong></div><div class="progress" style="height:8px"><div class="progress-bar bg-success" style="width:'+w+'%"></div></div></div>';}).join('')+'</div>';}
  async function openCampaign(id){ if(!can(id?'update':'create'))return toast('Tài khoản không có quyền thao tác','warning'); await catalogs(); const f=$('#contributionForm'); f.reset(); f.elements.id.value=''; f.elements.year.value=new Date().getFullYear(); f.elements.unit.value='VND/ho'; if(f.elements.unit_type)f.elements.unit_type.value='HOUSEHOLD'; f.elements.status.value='ACTIVE'; f.elements.required_type.value='REQUIRED'; if(f.elements.target_mode)f.elements.target_mode.value='ALL_HOUSEHOLDS'; if(id){const r=await req(API+'/'+id); Object.entries(r).forEach(([k,v])=>{if(f.elements[k]&&typeof v!=='object')f.elements[k].value=v??'';}); f.elements.id.value=r.id; applyCampaignConfig(f,r);} bootstrap.Modal.getOrCreateInstance($('#contributionModal')).show();}
  function campaignBody(form){const body=Object.fromEntries(new FormData(form).entries()); body.exemption_conditions=Array.from(form.querySelectorAll('[name="exemption_conditions"]:checked')).map(i=>i.value); body.target_config_json=JSON.stringify({mode:body.target_mode||'ALL_HOUSEHOLDS',age_from:body.target_age_from||null,age_to:body.target_age_to||null,note:body.target_note||''}); body.exemption_config_json=JSON.stringify({conditions:body.exemption_conditions,note:body.exemption_note||''}); return body;}
  function applyCampaignConfig(form,row){const target=row.target_config||{}; const exemption=row.exemption_config||{}; if(form.elements.target_mode)form.elements.target_mode.value=target.mode||'ALL_HOUSEHOLDS'; if(form.elements.target_age_from)form.elements.target_age_from.value=target.age_from||''; if(form.elements.target_age_to)form.elements.target_age_to.value=target.age_to||''; if(form.elements.target_note)form.elements.target_note.value=target.note||''; if(form.elements.exemption_note)form.elements.exemption_note.value=exemption.note||''; const selected=new Set(exemption.conditions||[]); form.querySelectorAll('[name="exemption_conditions"]').forEach(i=>{i.checked=selected.has(i.value);});}
  async function saveCampaign(e){e.preventDefault(); const f=e.currentTarget, body=campaignBody(f); try{await req(body.id?API+'/'+body.id:API,{method:body.id?'PUT':'POST',body}); bootstrap.Modal.getOrCreateInstance($('#contributionModal')).hide(); toast('Đã lưu đợt thu'); load();}catch(err){toast(err.message,'danger');}}
  async function removeCampaign(id){if(!can('delete'))return toast('Tài khoản không có quyền xóa','warning'); if(!confirm('Xóa đợt thu này?'))return; try{await req(API+'/'+id,{method:'DELETE'}); toast('Đã xóa đợt thu'); load();}catch(e){toast(e.message,'danger');}}
  async function loadTracking(){if(!state.campaign)return; const card=$('#contributionTrackingCard'),payment=$('#contributionPaymentFilter').value; card.classList.remove('d-none'); $('#contributionTrackingTitle').textContent='Theo dõi hộ - '+state.campaign.name; const p=new URLSearchParams({page:1,pageSize:100}); if(payment)p.set('payment_status',payment); const data=await req(API+'/'+state.campaign.id+'/households?'+p.toString()); $('#contributionTrackingTotal').textContent='Tổng số: '+num(data.total)+' hộ'; $('#contributionTrackingRows').innerHTML=(data.items||[]).map(trackRow).join('')||'<tr><td colspan="10" class="text-center text-muted py-4">Chưa có dữ liệu theo dõi</td></tr>'; $('#contributionTrackingRows').querySelectorAll('[data-pay]').forEach(b=>b.onclick=()=>openPayment(JSON.parse(b.dataset.pay))); if(typeof thon09SyncResponsiveTableLabels==='function')thon09SyncResponsiveTableLabels(card);}
  function trackRow(r){return '<tr><td>'+esc(r.household_code)+'</td><td><strong>'+esc(r.head_citizen_name)+'</strong><div class="small text-muted">Thu: '+num(r.eligible_count)+' / Mien: '+num(r.exempt_count)+'</div></td><td>'+esc(r.address)+'</td><td><span class="badge text-bg-light">'+esc(r.payment_status_label)+'</span></td><td>'+money(r.expected_amount)+'<div class="small text-muted">Da nop: '+money(r.paid_amount)+'</div></td><td>'+money(r.debt_amount)+'</td><td>'+esc(r.paid_at||'')+'</td><td>'+esc(r.collector_name)+'<div class="small text-muted">'+esc(r.payment_method_label||'')+'</div></td><td>'+esc(r.receipt_number)+'</td><td class="text-end"><button class="btn btn-sm btn-outline-primary" data-pay=\''+esc(JSON.stringify(r))+'\'><i class="fa-solid fa-pen"></i></button></td></tr>';}
  async function openPayment(r){if(!can('update'))return toast('Tài khoản không có quyền thao tác','warning'); await catalogs(); const f=$('#contributionPaymentForm'); f.reset(); Object.entries(r).forEach(([k,v])=>{if(f.elements[k])f.elements[k].value=v??'';}); f.elements.campaign_id.value=state.campaign.id; f.elements.household_id.value=r.household_id; $('#contributionPaymentHousehold').textContent=r.household_code+' - '+r.head_citizen_name; bootstrap.Modal.getOrCreateInstance($('#contributionPaymentModal')).show();}
  async function savePayment(e){e.preventDefault(); const f=e.currentTarget, body=Object.fromEntries(new FormData(f).entries()); try{await req(API+'/'+body.campaign_id+'/households/'+body.household_id,{method:'PUT',body}); bootstrap.Modal.getOrCreateInstance($('#contributionPaymentModal')).hide(); toast('Đã cập nhật đóng góp hộ'); loadTracking(); dashboard();}catch(err){toast(err.message,'danger');}}
  function exportReport(format){const p=params(); p.set('type','contributions'); if(state.campaign)p.set('campaign_id',state.campaign.id); window.open((format==='pdf'?'/api/reports/export-pdf':'/api/reports/export-excel')+'?'+p.toString(),'_blank','noopener');}
  function debounce(fn,ms){let t;return function(){clearTimeout(t);t=setTimeout(()=>fn.apply(this,arguments),ms);};}
})();
